mapper.select:
SELECT * FROM body_measurement
WHERE user_id = #{userId} AND record_date BETWEEN #{startDate} AND #{endDate}
ORDER BY record_date

mapper.update:
UPDATE body_measurement SET chest_cm = #{chestCm}, waist_cm = #{waistCm},
left_arm_cm = #{leftArmCm}, right_arm_cm = #{rightArmCm}, left_thigh_cm = #{leftThighCm},
right_thigh_cm = #{rightThighCm}, hip_cm = #{hipCm}, neck_cm = #{neckCm}, note = #{note}
WHERE id = #{id}
